# Databricks notebook source
# MAGIC %md
# MAGIC # Setup — Pricing Workbench v2
# MAGIC
# MAGIC Creates the schema, volumes, and app operational tables. Everything else
# MAGIC (reference data, dimensions, facts, features) is generated by dedicated
# MAGIC notebooks downstream.

# COMMAND ----------

dbutils.widgets.text("catalog_name", "lr_serverless_aws_us_catalog")
dbutils.widgets.text("schema_name",  "pricing_workbench")
dbutils.widgets.text("volume_name",  "external_landing")

catalog = dbutils.widgets.get("catalog_name")
schema  = dbutils.widgets.get("schema_name")
volume  = dbutils.widgets.get("volume_name")

fqn = f"{catalog}.{schema}"

# COMMAND ----------

# MAGIC %md
# MAGIC ## Schema + volumes

# COMMAND ----------

spark.sql(f"CREATE SCHEMA IF NOT EXISTS {fqn}")
print(f"✓ schema {fqn}")

for vol_name in ["external_landing", "saved_payloads", "reports", "raw_data"]:
    spark.sql(f"CREATE VOLUME IF NOT EXISTS {fqn}.{vol_name}")
    print(f"✓ volume {fqn}.{vol_name}")

# COMMAND ----------

# MAGIC %md
# MAGIC ## App operational tables
# MAGIC These are owned by the FastAPI app — dataset approval decisions, immutable
# MAGIC audit log. Created here so the app can assume they exist.

# COMMAND ----------

spark.sql(f"""
    CREATE TABLE IF NOT EXISTS {fqn}.app_audit_log (
        event_id        STRING      COMMENT 'UUID for the event',
        event_type      STRING      COMMENT 'dataset_approved, model_decision, agent_action, etc.',
        entity_type     STRING      COMMENT 'dataset, model, feature, endpoint, factory_run, policy, quote',
        entity_id       STRING      COMMENT 'Identifier of the entity acted upon',
        entity_version  STRING      COMMENT 'Version or snapshot reference',
        user_id         STRING      COMMENT 'Who triggered the event',
        timestamp       TIMESTAMP   COMMENT 'When the event occurred (UTC)',
        details         STRING      COMMENT 'JSON blob with event-specific metadata',
        source          STRING      COMMENT 'app | notebook | job | api'
    )
    COMMENT 'Immutable audit trail for all Pricing Workbench v2 events — dataset approvals, model decisions, agent interactions, factory run submissions, etc.'
""")
print(f"✓ {fqn}.app_audit_log")

spark.sql(f"""
    CREATE TABLE IF NOT EXISTS {fqn}.app_dataset_approvals (
        approval_id         STRING      COMMENT 'UUID for the decision',
        dataset_name        STRING      COMMENT 'Matches EXTERNAL_DATASETS key in the app',
        dataset_version     STRING      COMMENT 'Delta version or ingestion batch ID at time of decision',
        decision            STRING      COMMENT 'approved | rejected',
        reviewer            STRING      COMMENT 'Actuary or underwriter who decided',
        reviewer_notes      STRING      COMMENT 'Free-form note attached to the decision',
        reviewed_at         TIMESTAMP   COMMENT 'When the decision was recorded',
        raw_row_count       BIGINT      COMMENT 'Row count at raw layer at decision time',
        silver_row_count    BIGINT      COMMENT 'Row count at silver layer at decision time',
        rows_dropped_by_dq  INT         COMMENT 'Rows dropped by DLT expectations'
    )
    COMMENT 'HITL actuary/underwriter approval decisions per ingested dataset version.'
""")
print(f"✓ {fqn}.app_dataset_approvals")

# COMMAND ----------

# MAGIC %md
# MAGIC ## Summary

# COMMAND ----------

print(f"""
Setup complete.
  Catalog:  {catalog}
  Schema:   {schema}
  Volumes:  external_landing, saved_payloads, reports, raw_data
  Tables:   app_audit_log, app_dataset_approvals

Next: run the reference-data generation + ingestion jobs (Phase 1c).
""")
